INSERT INTO `notification_templates` VALUES (1,'hadir_masuk','Assalamualaikum Warahmatullahi Wabarakatuh\r\n\r\nDengan hormat Bapak/Ibu Wali Murid,\r\n\r\nKami dengan senang hati menyampaikan informasi kehadiran putra/putri Anda di *MAN 1 KOTA BANDUNG*:\r\n\r\n👤 Nama Siswa: *{nama}*\r\n🎓 Kelas: *{kelas}*\r\n📅 Hari: _{hari}_\r\n📆 Tanggal: _{tanggal}_\r\n🕐 Jam Masuk: *{jam}*\r\n✅ Status Kehadiran: *{status}*\r\n🏫 Lembaga: *MAN 1 KOTA BANDUNG*\r\n📝 Keterangan: _{keterangan}_\r\n\r\nKami berharap putra/putri Anda terus disiplin dan semangat dalam menuntut ilmu. _Dukungan dan perhatian Bapak/Ibu sangat berperan penting dalam kesuksesan pembelajaran._ Semoga Allah SWT memberikan kemudahan dan berkah atas setiap langkah mereka.\r\n\r\nTerima kasih atas kepercayaan yang telah diberikan kepada *MAN 1 KOTA BANDUNG*.\r\n\r\nWassalamualaikum Warahmatullahi Wabarakatuh','2026-05-09 01:54:30','2026-05-09 01:54:30'),(2,'terlambat_masuk','Assalamualaikum Warahmatullahi Wabarakatuh\r\n\r\nDengan hormat Bapak/Ibu Wali Murid,\r\n\r\nKami sampaikan informasi bahwa putra/putri Anda tercatat _terlambat_ masuk di *MAN 1 KOTA BANDUNG*:\r\n\r\n👤 Nama Siswa: *{nama}*\r\n🎓 Kelas: *{kelas}*\r\n📅 Hari: _{hari}_\r\n📆 Tanggal: _{tanggal}_\r\n🕐 Jam Masuk: *{jam}*\r\n⏱️ Status Kehadiran: *TERLAMBAT*\r\n🏫 Lembaga: *MAN 1 KOTA BANDUNG*\r\n📝 Keterangan: _{keterangan}_\r\n\r\nKami berharap Bapak/Ibu dapat memberikan bimbingan dan motivasi kepada putra/putri agar lebih disiplin dalam manajemen waktu. _Kedisiplinan adalah fondasi penting dalam mencapai kesuksesan akademik dan karakter yang baik._ Semoga Allah SWT memberi kemudahan dan kesadaran untuk selalu tepat waktu.\r\n\r\nTerima kasih atas perhatian dan kerjasama Bapak/Ibu dengan *MAN 1 KOTA BANDUNG*.\r\n\r\nWassalamualaikum Warahmatullahi Wabarakatuh','2026-05-09 01:56:52','2026-05-09 01:56:52'),(3,'sakit_masuk','Assalamualaikum Warahmatullahi Wabarakatuh\r\n\r\nDengan hormat Bapak/Ibu Wali Murid,\r\n\r\nKami sampaikan informasi bahwa putra/putri Anda tercatat _tidak hadir_ dengan status izin/sakit di *MAN 1 KOTA BANDUNG*:\r\n\r\n👤 Nama Siswa: *{nama}*\r\n🎓 Kelas: *{kelas}*\r\n📅 Hari: _{hari}_\r\n📆 Tanggal: _{tanggal}_\r\n🕐 Jam Masuk: *{jam}*\r\n✋ Status Kehadiran: *IZIN/SAKIT*\r\n🏫 Lembaga: *MAN 1 KOTA BANDUNG*\r\n📝 Keterangan: _{keterangan}_\r\n\r\nKami turut prihatin atas kondisi putra/putri Anda. _Kami berharap segera pulih dan kembali bersemangat belajar bersama kami._ Mohon untuk mengirimkan surat keterangan dari orang tua atau surat keterangan sakit dari tenaga medis sesuai ketentuan yang berlaku di sekolah kami.\r\n\r\nSemoga Allah SWT memberikan kesehatan dan kesembuhan untuk putra/putri Bapak/Ibu.\r\n\r\nTerima kasih atas perhatian dan kerjasama dengan *MAN 1 KOTA BANDUNG*.\r\n\r\nWassalamualaikum Warahmatullahi Wabarakatuh','2026-05-09 01:58:07','2026-05-09 01:58:07'),(4,'izin_masuk','Assalamualaikum Warahmatullahi Wabarakatuh\r\n\r\nDengan hormat Bapak/Ibu Wali Murid,\r\n\r\nKami sampaikan informasi bahwa putra/putri Anda tercatat _tidak hadir_ dengan status izin keperluan di *MAN 1 KOTA BANDUNG*:\r\n\r\n👤 Nama Siswa: *{nama}*\r\n🎓 Kelas: *{kelas}*\r\n📅 Hari: _{hari}_\r\n📆 Tanggal: _{tanggal}_\r\n🕐 Jam Masuk: *{jam}*\r\n📋 Status Kehadiran: *IZIN KEPERLUAN*\r\n🏫 Lembaga: *MAN 1 KOTA BANDUNG*\r\n📝 Keterangan: _{keterangan}_\r\n\r\nKami menghargai transparansi yang diberikan melalui pemberitahuan izin keperluan ini. _Kami berharap putra/putri Anda dapat menyelesaikan keperluan dengan baik dan kembali fokus dalam proses belajar mengajar._ Mohon pastikan izin telah sesuai dengan prosedur yang berlaku di sekolah kami.\r\n\r\nSemoga setiap waktu yang digunakan memberikan manfaat dan berkah bagi putra/putri Anda.\r\n\r\nTerima kasih atas perhatian dan kerjasama dengan *MAN 1 KOTA BANDUNG*.\r\n\r\nWassalamualaikum Warahmatullahi Wabarakatuh','2026-05-09 01:59:42','2026-05-09 01:59:42'),(5,'alpha_masuk','Assalamualaikum Warahmatullahi Wabarakatuh\r\n\r\nDengan hormat Bapak/Ibu Wali Murid,\r\n\r\nKami sampaikan informasi penting bahwa putra/putri Anda tercatat _tidak hadir_ tanpa keterangan di *MAN 1 KOTA BANDUNG*:\r\n\r\n👤 Nama Siswa: *{nama}*\r\n🎓 Kelas: *{kelas}*\r\n📅 Hari: _{hari}_\r\n📆 Tanggal: _{tanggal}_\r\n🕐 Jam Masuk: *{jam}*\r\n❌ Status Kehadiran: *ALFA (TIDAK HADIR)*\r\n🏫 Lembaga: *MAN 1 KOTA BANDUNG*\r\n📝 Keterangan: _{keterangan}_\r\n\r\n_Hal ini memerlukan perhatian khusus dari Bapak/Ibu._ Kami mengharapkan segera mendapatkan penjelasan atau surat keterangan dari orang tua mengenai ketidakhadiran putra/putri Anda. Ketidakhadiran tanpa keterangan dapat mempengaruhi prestasi akademik dan reputasi siswa.\r\n\r\nSemoga Bapak/Ibu dapat memberikan bimbingan agar putra/putri lebih bertanggung jawab dan disiplin dalam kehadiran sekolah.\r\n\r\nTerima kasih atas respons dan kerjasama Bapak/Ibu dengan *MAN 1 KOTA BANDUNG*.\r\n\r\nWassalamualaikum Warahmatullahi Wabarakatuh','2026-05-09 02:01:32','2026-05-09 02:01:32'),(6,'pulang','Assalamualaikum Warahmatullahi Wabarakatuh\r\n\r\nDengan hormat Bapak/Ibu Wali Murid,\r\n\r\nKami informasikan bahwa putra/putri Anda telah _pulang_ dari *MAN 1 KOTA BANDUNG*:\r\n\r\n👤 Nama Siswa: *{nama}*\r\n🎓 Kelas: *{kelas}*\r\n📅 Hari: _{hari}_\r\n📆 Tanggal: _{tanggal}_\r\n🕐 Jam Pulang: *{jam}*\r\n🏫 Lembaga: *MAN 1 KOTA BANDUNG*\r\n📝 Keterangan: _{keterangan}_\r\n\r\n_Kami pastikan putra/putri Anda dalam keadaan sehat dan aman._ Mohon Bapak/Ibu memastikan putra/putri tiba dengan selamat di rumah.\r\n\r\nTerima kasih atas kepercayaan dan kerjasama dengan *MAN 1 KOTA BANDUNG*.\r\n\r\nWassalamualaikum Warahmatullahi Wabarakatuh','2026-05-09 02:10:28','2026-05-09 02:10:28'),(7,'pelepasan_hadir','Assalamu\'alaikum Wr. Wb.\r\nYth. Bapak/Ibu Orang Tua/Wali dari *{nama}* – Kelas *{kelas}*,\r\n\r\nDengan hormat, kami sampaikan bahwa putra/putri Bapak/Ibu telah tercatat hadir pada acara *Pelepasan Kelas XII {lembaga}* pada pukul *{jam}* WIB.\r\n\r\nKehadiran ini menjadi kebanggaan tersendiri bagi kami dan semoga menjadi awal yang baik bagi langkah putra/putri menuju masa depan yang gemilang.\r\n\r\nWassalamu\'alaikum Wr. Wb.\r\nAdmin Kesiswaan {lembaga}','2026-06-13 04:42:15','2026-06-13 04:42:15');
/*!40000 ALTER TABLE `notification_templates` ENABLE KEYS */;
UNLOCK TABLES;

